import{_ as e,a,b as d,c as o,d as r}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as n,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"新增 OneDrive 渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/onedrive.md","filePath":"zh-TW/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"zh-TW/upload/onedrive.md"};function p(h,t,b,m,g,u){return n(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="新增-onedrive-渠道" tabindex="-1">新增 OneDrive 渠道 <a class="header-anchor" href="#新增-onedrive-渠道" aria-label="Permalink to &quot;新增 OneDrive 渠道&quot;">​</a></h1><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>Microsoft 帳號</td><td>登入 Microsoft 後台並授權 OneDrive</td></tr><tr><td>ImgBed 網域</td><td>設定回呼網址</td></tr><tr><td>一個 App registration</td><td>取得 <code>Client ID</code> 和 <code>Client Secret</code></td></tr><tr><td>OneDrive 帳號</td><td>實際存放檔案</td></tr></tbody></table><h2 id="新增步驟" tabindex="-1">新增步驟 <a class="header-anchor" href="#新增步驟" aria-label="Permalink to &quot;新增步驟&quot;">​</a></h2><h3 id="第一步-進入-microsoft-entra-id" tabindex="-1">第一步：進入 Microsoft Entra ID <a class="header-anchor" href="#第一步-進入-microsoft-entra-id" aria-label="Permalink to &quot;第一步：進入 Microsoft Entra ID&quot;">​</a></h3><ol><li>打開 <code>portal.azure.com</code>。</li><li>上方搜尋 <code>Microsoft Entra ID</code>。</li><li>如果下拉選單沒有目標入口，就點：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>繼續在 Microsoft Entra ID 中搜尋</span></span></code></pre></div><ol start="4"><li>進入 <code>Microsoft Entra ID</code>。</li><li>打開 <code>App registrations</code>。</li><li>點 <code>New registration</code>。</li></ol><h3 id="第二步-建立應用程式" tabindex="-1">第二步：建立應用程式 <a class="header-anchor" href="#第二步-建立應用程式" aria-label="Permalink to &quot;第二步：建立應用程式&quot;">​</a></h3><p>在 <code>New registration</code> 頁面填：</p><table tabindex="0"><thead><tr><th>頁面欄位</th><th>填寫方式</th></tr></thead><tbody><tr><td>Name</td><td>自己取，例如 <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>依下表選</td></tr><tr><td>Redirect URI 類型</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://你的網域/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>帳號類型建議：</p><table tabindex="0"><thead><tr><th>使用情境</th><th>Supported account types</th></tr></thead><tbody><tr><td>個人 OneDrive</td><td>選個人 Microsoft 帳號</td></tr><tr><td>個人與組織帳號都要支援</td><td>選同時支援個人和組織帳號</td></tr><tr><td>只給公司 / 學校 OneDrive 用</td><td>選組織帳號</td></tr></tbody></table><p>填完後按註冊。</p><p><img src="'+e+'" alt="建立 OneDrive 應用" loading="lazy"></p><h3 id="第三步-記下應用程式資訊" tabindex="-1">第三步：記下應用程式資訊 <a class="header-anchor" href="#第三步-記下應用程式資訊" aria-label="Permalink to &quot;第三步：記下應用程式資訊&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Microsoft 後台欄位</th><th>ImgBed 欄位</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td>組織帳號情境下的 <code>Tenant ID</code></td></tr></tbody></table><p><img src="'+a+'" alt="查看 Application ID 和 Tenant ID" loading="lazy"></p><h3 id="第四步-建立-client-secret" tabindex="-1">第四步：建立 Client Secret <a class="header-anchor" href="#第四步-建立-client-secret" aria-label="Permalink to &quot;第四步：建立 Client Secret&quot;">​</a></h3><ol><li>進入 <code>Certificates &amp; secrets</code>。</li><li>點 <code>New client secret</code>。</li><li>名稱自己取。</li><li>到期時間依需求選。</li><li>建立後立刻複製 <code>Value</code>。</li></ol><p><img src="'+d+'" alt="保存 Client Secret Value" loading="lazy"></p><h3 id="第五步-新增權限" tabindex="-1">第五步：新增權限 <a class="header-anchor" href="#第五步-新增權限" aria-label="Permalink to &quot;第五步：新增權限&quot;">​</a></h3><ol><li>進入 <code>API permissions</code>。</li><li>點 <code>Add a permission</code>。</li><li>選 <code>Microsoft Graph</code>。</li><li>選 <code>Delegated permissions</code>。</li><li>加入：</li></ol><table tabindex="0"><thead><tr><th>權限</th><th>作用</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>上傳、建目錄、刪檔</td></tr><tr><td><code>offline_access</code></td><td>取得 Refresh Token</td></tr><tr><td><code>User.Read</code></td><td>讀取帳號資訊和容量</td></tr></tbody></table><h3 id="第六步-回-imgbed-填寫-onedrive-渠道" tabindex="-1">第六步：回 ImgBed 填寫 OneDrive 渠道 <a class="header-anchor" href="#第六步-回-imgbed-填寫-onedrive-渠道" aria-label="Permalink to &quot;第六步：回 ImgBed 填寫 OneDrive 渠道&quot;">​</a></h3><table tabindex="0"><thead><tr><th>頁面欄位</th><th>填寫內容</th></tr></thead><tbody><tr><td>渠道名稱</td><td>自己取，例如 <code>OneDrive主帳號</code></td></tr><tr><td>Client ID</td><td>Microsoft 的 <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>剛才複製的 Client Secret Value</td></tr><tr><td>Tenant ID</td><td>依下表填</td></tr><tr><td>Refresh Token</td><td>先留空</td></tr><tr><td>根目錄</td><td>選填，預設 <code>imgbed</code></td></tr><tr><td>備註</td><td>選填</td></tr></tbody></table><p><img src="'+o+'" alt="回 ImgBed 填寫 OneDrive 設定" loading="lazy"></p><p><code>Tenant ID</code> 填法：</p><table tabindex="0"><thead><tr><th>你選的帳號類型</th><th>ImgBed 裡的 <code>Tenant ID</code></th></tr></thead><tbody><tr><td>個人帳號</td><td><code>consumers</code></td></tr><tr><td>個人 + 組織帳號</td><td><code>common</code></td></tr><tr><td>只給目前組織</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="第七步-取得-refresh-token" tabindex="-1">第七步：取得 Refresh Token <a class="header-anchor" href="#第七步-取得-refresh-token" aria-label="Permalink to &quot;第七步：取得 Refresh Token&quot;">​</a></h3><ol><li>在 ImgBed 點「取得 Token」。</li><li>登入要綁定的 Microsoft 帳號。</li><li>依提示授權。</li><li>成功後，回呼頁會顯示 <code>Refresh Token</code>。</li><li>複製它。</li><li>回到 ImgBed，貼到 <code>Refresh Token</code> 欄位。</li></ol><p><img src="'+r+`" alt="複製 Refresh Token" loading="lazy"></p><h3 id="第八步-儲存渠道" tabindex="-1">第八步：儲存渠道 <a class="header-anchor" href="#第八步-儲存渠道" aria-label="Permalink to &quot;第八步：儲存渠道&quot;">​</a></h3><p>欄位填好後直接儲存。</p><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打開 portal.azure.com</span></span>
<span class="line"><span>-&gt; 搜尋 Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; 進入 App registrations</span></span>
<span class="line"><span>-&gt; New registration</span></span>
<span class="line"><span>-&gt; 填 Name / Supported account types / Web 回呼網址</span></span>
<span class="line"><span>-&gt; 複製 Application (client) ID</span></span>
<span class="line"><span>-&gt; 建立 Client Secret</span></span>
<span class="line"><span>-&gt; 新增 Microsoft Graph 權限</span></span>
<span class="line"><span>-&gt; 回 ImgBed 填 Client ID / Client Secret / Tenant ID</span></span>
<span class="line"><span>-&gt; 點取得 Token</span></span>
<span class="line"><span>-&gt; 複製 Refresh Token</span></span>
<span class="line"><span>-&gt; 貼回 ImgBed 儲存</span></span></code></pre></div>`,36)])])}const v=i(c,[["render",p]]);export{I as __pageData,v as default};
